private void xrTableCell44_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        XRTableCell cell = sender as XRTableCell;
    if (cell == null)
        return;

    decimal fabw = Convert.ToDecimal(GetCurrentColumnValue("FABW") ?? 0);
    decimal stanBodyWeight = Convert.ToDecimal(GetCurrentColumnValue("StanBodyWeight") ?? 0);

    decimal diff = fabw - stanBodyWeight;
    if (diff != 0){
        decimal result = diff ;
        cell.Text = result.ToString("N2");

    }
    else{

        cell.Text = "0.00";  
    }

    if(diff != 0){
        sumStdVSactReport  += diff ;
        sumNonZeroBWvsStdReport++ ;

      }
}


